using BenchmarkDotNet.Attributes;
using System.Collections.ObjectModel;
using TextAnalysis;

public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // ~200 words of representative English text
        const string text =
            "The quick brown fox jumps over the lazy dog and then runs across the field to find shelter " +
            "under a large oak tree that has been standing for hundreds of years in the countryside near " +
            "the village where farmers grow wheat and barley during the summer months while their children " +
            "play in the meadows and swim in the river that flows gently through the valley between two " +
            "tall mountains covered with snow and ice even during the warmest days of July when tourists " +
            "come from distant cities to enjoy the fresh air and beautiful scenery that this region has " +
            "to offer along with traditional food and music that has been passed down through generations " +
            "of families who have lived here since the founding of the settlement many centuries ago when " +
            "explorers first discovered this hidden paradise tucked away behind the great mountain range " +
            "that separates the coastal plains from the interior highlands where wild animals roam freely " +
            "across vast expanses of untouched wilderness filled with ancient forests and crystal clear " +
            "streams that provide fresh water to all the surrounding communities and their livestock";

        _analyzer = new TextAnalyzer(text);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public ReadOnlyCollection<int> WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

